INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Real-time dashboards$q$, $q$Build customizable, TV-ready dashboards that display live KPIs pulled from connected business systems.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$100+ integrations$q$, $q$Connects to CRMs, help desks, telephony tools and SQL databases to centralize performance data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Gamification and contests$q$, $q$Run sales contests, leaderboards and a virtual reward store to motivate teams.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Achievements and notifications$q$, $q$Trigger automated badges and alerts when individuals or teams hit performance milestones.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Coaching and training module$q$, $q$Optional add-on for running one-on-ones and quizzes tied to performance data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Single sign-on and API access$q$, $q$SAML2 single sign-on and an open API for building custom data connections and reports.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Wide range of native integrations with popular CRMs and help desks$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Strong gamification features that go beyond basic dashboarding$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Dashboards are easy to build without technical or engineering resources$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Responsive chat, email and phone support depending on plan$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$No free plan and pricing is relatively high for small teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Per-license pricing can get expensive as headcount grows$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Gamification features like contests are locked behind the higher-priced Large plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Less suited to deep, ad hoc business intelligence analysis than dedicated BI tools$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$What is Plecto used for?$q$, $q$Plecto is used to build real-time KPI dashboards and gamify performance for sales, support and customer success teams by connecting to CRMs, help desks and other business systems.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Does Plecto have a free plan?$q$, $q$No, Plecto does not offer a permanent free plan. Pricing starts with the paid Medium tier, though trials may be available on request.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$How much does Plecto cost?$q$, $q$Plecto's Medium plan starts at around $300 per month billed annually for 10 tracked licenses, with the Large plan starting around $465 per month for 10 licenses.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Where is Plecto based?$q$, $q$Plecto is headquartered in Aarhus, Denmark, and was founded in 2012.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$What integrations does Plecto support?$q$, $q$Plecto integrates with over 100 systems, including Salesforce, HubSpot, Pipedrive, Zendesk, Intercom and generic SQL databases.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Is Plecto a business intelligence tool or a gamification tool?$q$, $q$Plecto combines both: it functions as a real-time BI dashboard tool while also offering gamification features like contests, leaderboards and rewards.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$What are the main alternatives to Plecto?$q$, $q$Common alternatives include Databox, Geckoboard, Klipfolio and Grow for dashboards, and Ambition or Spinify for sales gamification specifically.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Sales team performance tracking$q$, $q$Sales managers use Plecto to display live pipeline, quota attainment and call metrics on office dashboards to keep reps aligned and motivated.$q$, $q$Sales operations and sales managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Support and call center monitoring$q$, $q$Support leaders track ticket volume, resolution time and CSAT scores in real time to spot bottlenecks and recognize top performers.$q$, $q$Customer support and call center managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Cross-team gamified competition$q$, $q$Revenue teams run contests and leaderboards across departments to drive short-term pushes on specific metrics like new bookings or renewals.$q$, $q$Revenue operations and team leads$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Medium$q$, $q$$300/month$q$, $q$Annual (for 10 tracked licenses)$q$, NULL, $q$["Unlimited dashboards","Unlimited data sources","API access","Single sign-on (SAML2)","Achievements and notifications","Chat and email support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Large$q$, $q$$465/month$q$, $q$Annual (for 10 tracked licenses)$q$, NULL, $q$["Everything in Medium","Sales contests and reward store","Customer success manager","SQL integrations","Custom themes and IP restriction","Phone support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Everything in Large","On-site setup","Custom integrations","Volume discounts","Custom NDA and DPA"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Plecto is a real-time performance dashboard and gamification platform built for sales, support and customer success teams. It connects to CRMs, help desks, telephony systems and databases to pull live metrics and display them on customizable dashboards that teams can watch on office screens or personal devices.$q$, $q$The company was founded in 2012 in Aarhus, Denmark, and remains a privately held, relatively small software vendor focused specifically on the intersection of business intelligence and employee motivation, rather than broad enterprise BI.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Plecto's core product is its dashboard builder, which pulls in data from more than 100 integrations, including Salesforce, HubSpot, Pipedrive, Zendesk and generic SQL databases, and displays it through customizable widgets, charts and leaderboards.$q$, $q$On top of the dashboards, Plecto layers gamification tools such as sales contests, achievement badges, a virtual reward store and automated notifications, which are designed to make performance visible and drive friendly competition across a team.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('794737f5-a11c-4c4b-bd01-c5bd60d80316', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Plecto uses per-license, annually billed subscription pricing rather than a free plan. The Medium plan starts at around $300 per month for 10 tracked licenses and covers unlimited dashboards and data sources, while the Large plan adds gamification and coaching features for roughly $465 per month for 10 licenses.$q$, $q$An Enterprise tier is available with custom pricing for organizations that need on-site setup, custom integrations or volume discounts, and optional add-on modules like Dynamic Dashboards and Coaching and Training are billed separately.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Smart company cards$q$, $q$Issue physical and virtual cards to employees with configurable limits and instant card freezing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Automated receipt capture$q$, $q$Employees photograph receipts on their phone immediately after a purchase, syncing with the transaction.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Approval workflows$q$, $q$Set flexible, rules-based approval chains for spending above defined thresholds.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Accounting integrations$q$, $q$Sync transactions and categories directly with tools like Xero, QuickBooks and NetSuite.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Budgeting and reporting$q$, $q$Set department or project budgets and track spend against them in real time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$AI-powered spend guidelines$q$, $q$Automatically flag transactions that fall outside company spending policy for review.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Reduces manual expense reports and reimbursement delays for employees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Real-time visibility into company spending for finance teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Strong accounting and HRIS integrations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Cards can be issued and frozen instantly through the app$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$No free tier; pricing is per-user and can add up for larger teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Full feature set (budgeting, cashback, multi-entity) requires higher-priced plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Primarily focused on European businesses, with a smaller footprint outside Europe$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Business tier requires contacting sales rather than transparent self-serve pricing$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$What is Pleo used for?$q$, $q$Pleo is used by companies to issue smart corporate cards to employees and automate expense tracking, approvals and accounting reconciliation.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$How much does Pleo cost?$q$, $q$Pleo's Essential plan starts at around $39 per month billed annually for 3 users, with Advanced and custom-priced Business tiers available for more features.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Who founded Pleo?$q$, $q$Pleo was founded in 2015 by Jeppe Rindom and Niccolo Perra in Copenhagen, Denmark.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Does Pleo offer physical and virtual cards?$q$, $q$Yes, Pleo issues both physical and virtual cards to employees with configurable spending limits.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Does Pleo integrate with accounting software?$q$, $q$Yes, Pleo integrates with accounting systems such as Xero, QuickBooks and NetSuite, along with various HRIS platforms on higher tiers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Is Pleo available outside Europe?$q$, $q$Pleo primarily serves businesses in the UK and continental Europe, and is best known and most established in that market.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$What are the main alternatives to Pleo?$q$, $q$Common alternatives include Spendesk, Payhawk, Soldo, Ramp and Expensify.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Employee-driven purchasing$q$, $q$Companies issue Pleo cards to employees so they can make work-related purchases instantly without waiting for reimbursement.$q$, $q$Finance teams and employees at SMBs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Expense automation for finance teams$q$, $q$Finance teams use Pleo to eliminate manual receipt collection and speed up monthly reconciliation with accounting software.$q$, $q$Finance and accounting departments$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Multi-entity spend control$q$, $q$Larger or multi-subsidiary organizations use Pleo Business to manage budgets, approvals and reporting across multiple legal entities.$q$, $q$Finance leaders at multi-entity or scaling companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Essential$q$, $q$$39/month$q$, $q$Annual (includes 3 users, $11/additional user)$q$, NULL, $q$["Physical and virtual cards","Accounting integrations","Reimbursements and mileage tracking","AI-powered spend guidelines","Chat support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Advanced$q$, $q$$99/month$q$, $q$Annual (includes 3 users, $15/additional user)$q$, NULL, $q$["Everything in Essential","Budgeting tools","HRIS integrations","Cashback (eligible customers)","Advanced approval workflows"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$Business$q$, $q$Custom (bespoke pricing)$q$, $q$Annual, custom$q$, NULL, $q$["Everything in Advanced","Multi-entity management","Premium integrations","AI-powered expense review","Dedicated customer success management"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pleo is a company spend management platform that issues smart corporate cards to employees, paired with software that automates receipt capture, expense categorization and approval workflows so finance teams no longer have to chase paper receipts or manual expense reports.$q$, $q$Founded in Copenhagen in 2015 by Jeppe Rindom and Niccolo Perra, Pleo has grown into one of the larger European fintechs in the spend management category, raising substantial venture funding and expanding across the UK and continental Europe.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Pleo issues physical and virtual cards to employees with configurable spending limits, so purchases happen instantly without needing pre-approval for every transaction, while finance teams retain real-time visibility into every charge.$q$, $q$The platform also handles invoice management, mileage and per diem tracking, reimbursements for out-of-pocket spend, and accounting system integrations, with AI-powered spend guidelines that flag out-of-policy transactions for review.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f4a927a2-feba-4930-ad55-823b90a5c145', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pleo prices in three tiers. Essential starts at about $39 per month billed annually for 3 users plus a per-additional-user fee, and covers core cards, reimbursements and accounting integrations.$q$, $q$Advanced adds budgeting tools, HRIS integrations and cashback eligibility for around $99 per month billed annually, while Business is custom-priced and adds multi-entity management, premium integrations and dedicated customer success support for larger organizations.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$ActivityPub federation$q$, $q$Interoperates natively with Mastodon, Akkoma, Misskey and other Fediverse platforms.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Lightweight resource footprint$q$, $q$Runs efficiently on low-spec, low-cost servers thanks to its Elixir/BEAM architecture.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Message Rewrite Facility$q$, $q$A configurable policy engine for content moderation and federation control.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Mastodon and GNU social API compatibility$q$, $q$Works with existing Mastodon and GNU social mobile and desktop apps.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Multiple frontends$q$, $q$Supports different web client interfaces, including the default Pleroma-FE and alternatives.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Self-hosted moderation control$q$, $q$Instance admins fully control terms of service, moderation policy and federation rules.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Free and open source with no licensing costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Much lighter on server resources than Mastodon$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Compatible with existing Mastodon and GNU social client apps$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Full control over moderation, federation and data as a self-hosted instance$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Requires technical skill to install, configure and maintain a server$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Smaller, more fragmented community than Mastodon$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$No official commercial support or managed hosting from the core project$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Development pace has slowed relative to its fork, Akkoma$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$What is Pleroma?$q$, $q$Pleroma is a free, open-source microblogging server that implements ActivityPub, letting anyone self-host a federated social network node compatible with Mastodon and the Fediverse.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Is Pleroma free?$q$, $q$Yes, Pleroma is free and open-source software under the AGPLv3 license; the only cost is the server hosting you choose to run it on.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Who created Pleroma?$q$, $q$Pleroma was created in 2016 by a pseudonymous developer known as lain, with the first backend commit made in March 2017.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$How is Pleroma different from Mastodon?$q$, $q$Pleroma is designed to be significantly more lightweight and resource-efficient than Mastodon, making it cheaper to self-host, while Mastodon has a larger community and dedicated organizational backing.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$What is Akkoma and how does it relate to Pleroma?$q$, $q$Akkoma is a fork of Pleroma created in 2022 to support faster-paced development and more user customization.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Can Pleroma users interact with Mastodon users?$q$, $q$Yes, because both implement the ActivityPub protocol, Pleroma and Mastodon users can follow, reply to and interact with each other across instances.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Do I need technical skills to run Pleroma?$q$, $q$Yes, running a Pleroma instance requires comfort with server administration, though its lightweight requirements make it more accessible than heavier alternatives.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Personal or small community Fediverse instance$q$, $q$Individuals or small groups self-host a Pleroma server on an inexpensive VPS to have full control over their own corner of the Fediverse.$q$, $q$Privacy-focused individuals and small online communities$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Niche interest or topical instances$q$, $q$Communities centered on a specific topic or interest run a Pleroma instance with tailored moderation policy for their members.$q$, $q$Interest-based online communities and moderators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Low-budget federated hosting$q$, $q$Hosting providers or hobbyists choose Pleroma over heavier alternatives to keep server costs down while still joining the Fediverse.$q$, $q$Self-hosting enthusiasts and small hosting providers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$Self-Hosted$q$, $q$Free$q$, $q$Open source, one-time setup plus your own server hosting costs$q$, NULL, $q$["Full ActivityPub federation","Unlimited instance users (hardware-dependent)","Full moderation and admin control","Community support via forums and chat"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pleroma is an open-source, self-hosted microblogging server that speaks the ActivityPub protocol, meaning any Pleroma instance can follow, be followed by, and interact with users on Mastodon, Akkoma, Misskey and other Fediverse software.$q$, $q$Created in 2016 by a developer known by the pseudonym lain, Pleroma was built as a lighter-weight alternative to Mastodon, prioritizing low resource usage so instances can run affordably on modest hardware.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pleroma supports the core building blocks of a federated social network: posts with a default 5,000-character limit, media attachments, polls, and full ActivityPub federation with the wider Fediverse.$q$, $q$Administrators get granular control through the Message Rewrite Facility, a policy engine for content moderation and federation rules, and can choose from multiple frontends while supporting both the Mastodon and GNU social client APIs for compatibility with existing apps.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pleroma itself is entirely free and open source under the AGPLv3 license, with no paid tiers, subscriptions or vendor fees for the software.$q$, $q$The only real cost is server hosting, and because Pleroma is designed to be lightweight, it can run on inexpensive virtual private servers, making it one of the more affordable ways to self-host a federated social network node.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('87827575-d6b9-427d-9a29-d335e632d59f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Personal media streaming$q$, $q$Stream your own video, music and photo library to any device from a self-hosted or NAS-based Plex Media Server.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Automatic metadata and organization$q$, $q$Fetches posters, descriptions and episode data to organize a personal library like a commercial streaming catalog.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Free ad-supported streaming$q$, $q$Watch licensed movies and TV shows for free, supported by ads, without needing a Plex Pass.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Live TV and DVR$q$, $q$Connect an antenna or tuner to watch and record live over-the-air television through Plex.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Remote and offline access$q$, $q$Stream your library remotely over the internet, with Plex Pass enabling offline mobile sync.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Hardware-accelerated transcoding$q$, $q$Plex Pass unlocks GPU-accelerated transcoding for smoother playback on lower-powered servers.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Free core media server with no ongoing subscription required for personal libraries$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Polished, consistent apps across smart TVs, mobile, web and consoles$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Adds free ad-supported movies and shows on top of personal media$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Active development with regular new features like live TV and AI-assisted tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Lifetime Plex Pass price rose sharply to roughly $749.99 in 2026$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Requires a home server or NAS running continuously for full functionality$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Some premium features are locked behind the Plex Pass subscription$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Setup and library organization can be technical for non-tech-savvy users$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Is Plex free to use?$q$, $q$Yes, the core Plex Media Server and streaming your own library is free. Plex Pass is an optional paid subscription for premium features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$What does Plex Pass add?$q$, $q$Plex Pass adds hardware-accelerated transcoding, offline mobile sync, advanced parental controls, live TV/DVR and other premium features.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$How much does Plex Pass cost?$q$, $q$Plex Pass costs around $6.99 per month, about $69.99 per year, a new 5-year plan around $249.99, or a one-time lifetime purchase priced at roughly $749.99 as of mid-2026.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Who owns Plex?$q$, $q$Plex is developed by Plex Inc., a privately held company headquartered in Campbell, California, co-founded by Elan Feingold, Cayce Ullman and Scott Olechowski.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Do I need my own server to use Plex?$q$, $q$To stream your own media library, yes, you need Plex Media Server running on a computer or NAS device; the free ad-supported streaming catalog does not require this.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$What are the main alternatives to Plex?$q$, $q$The closest alternatives are Jellyfin, a free and fully open-source personal media server, and Emby, a similarly freemium self-hosted media server.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Can I watch Plex on smart TVs and consoles?$q$, $q$Yes, Plex has apps for most smart TVs, streaming devices, game consoles, mobile phones and web browsers.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Home media server for ripped or downloaded content$q$, $q$Home theater enthusiasts run Plex Media Server on a NAS or PC to stream their own movie, TV and music collections to every device in the house.$q$, $q$Home theater and NAS enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Free ad-supported streaming$q$, $q$Casual viewers use the Plex app to watch free, licensed movies and TV shows without needing their own media library.$q$, $q$Casual streaming viewers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Family photo and video backup$q$, $q$Families use Plex to organize and privately share photo and home video libraries across devices and household members.$q$, $q$Families and personal media archivists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Plex Media Server for personal libraries","Remote streaming to apps and devices","Free ad-supported movies and TV shows","Basic library organization and metadata"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Plex Pass Monthly$q$, $q$$6.99/month$q$, $q$Monthly$q$, NULL, $q$["Hardware-accelerated transcoding","Offline mobile sync","Advanced parental controls","Live TV and DVR","Early access to new features"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Plex Pass Annual$q$, $q$$69.99/year$q$, $q$Annual$q$, NULL, $q$["Everything in Plex Pass Monthly at a discounted annual rate"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$Plex Pass Lifetime$q$, $q$$749.99$q$, $q$One-time purchase$q$, NULL, $q$["Everything in Plex Pass, permanently, with a single one-time payment"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Plex is media server software paired with a streaming platform: it turns a user's own video, music and photo files into a personal, Netflix-style streaming service accessible from phones, smart TVs, consoles and browsers, while also offering a separate free, ad-supported catalog of licensed movies and shows.$q$, $q$Plex began as a 2007 side project porting the Kodi (then XBMC) media center to Mac OS X, was renamed Plex in 2008, and became a formally incorporated company, Plex Inc., in December 2009, headquartered in Campbell, California.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Plex Media Server indexes a user's personal media library, fetches metadata like posters and descriptions, and transcodes files on the fly so they play smoothly on virtually any device and network condition.$q$, $q$Beyond personal libraries, Plex offers free ad-supported movies and TV shows, live TV and DVR functionality with an antenna or tuner, music and podcast streaming, and photo backup and organization, unifying personal and licensed content in one app.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Plex Media Server and basic remote streaming of your own library are free to use. The optional Plex Pass subscription adds premium features like hardware-accelerated transcoding, offline mobile sync, advanced parental controls and live TV/DVR.$q$, $q$Plex Pass is available monthly (around $6.99), annually (around $69.99), as a new 5-year plan (around $249.99), or as a lifetime one-time purchase, which increased significantly to roughly $749.99 in mid-2026.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b7ba79dd-5c0b-4a49-8fbc-28ce57af66f6', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Enterprise-grade security$q$, $q$A long-standing security track record with regular audits and a dedicated security team within the Plone Foundation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Granular workflows and permissions$q$, $q$Built-in content approval workflows and fine-grained, role-based permission controls.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Headless and traditional delivery$q$, $q$REST API and Volto React frontend support both decoupled headless architectures and classic server-rendered sites.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Multilingual content management$q$, $q$Native support for managing and translating content across many languages within a single site.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Accessibility compliance$q$, $q$Built with accessibility standards in mind, helping public-sector and enterprise sites meet compliance requirements.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Python/Zope foundation$q$, $q$Built on the mature Zope application server, giving developers a robust, extensible Python framework underneath.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Completely free and open source with no licensing costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Strong reputation for security, making it popular with government and enterprise sites$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Flexible headless or traditional deployment via REST API and Volto$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Mature workflow, permissions and multilingual capabilities out of the box$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Steeper learning curve than mainstream CMS platforms like WordPress$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Smaller plugin/add-on ecosystem compared to WordPress or Drupal$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Requires Python hosting expertise, which is less common than PHP hosting$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$No official vendor support; relies on community and third-party integrators$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Is Plone free?$q$, $q$Yes, Plone is 100% free and open-source software with no licensing fees, governed by the nonprofit Plone Foundation.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Who created Plone?$q$, $q$Plone was created by Alexander Limi, Alan Runyan and Vidar Andersen, beginning in 1999 and first released publicly in October 2001.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$What is Plone built on?$q$, $q$Plone is built on the Zope application server and written primarily in Python, with a React-based frontend called Volto for modern and headless deployments.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Can Plone be used as a headless CMS?$q$, $q$Yes, Plone exposes a full REST API and supports headless deployments through its Volto React frontend, alongside traditional server-rendered sites.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Who uses Plone?$q$, $q$Plone is commonly used by government agencies, universities, large nonprofits and enterprises with strong security, workflow or multilingual requirements.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$How does Plone compare to WordPress?$q$, $q$Plone offers stronger built-in security, workflow and permissions capabilities suited to complex organizations, while WordPress has a much larger plugin ecosystem and gentler learning curve.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Does Plone offer paid support?$q$, $q$The Plone Foundation itself does not sell support, but independent Plone integrators and agencies offer paid implementation, hosting and support services.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Government and public-sector websites$q$, $q$Government agencies use Plone for its strong security track record and accessibility compliance for citizen-facing websites.$q$, $q$Government IT and digital services teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$University and large nonprofit content management$q$, $q$Universities and nonprofits use Plone to manage large, multilingual, multi-department websites with complex approval workflows.$q$, $q$Higher education and nonprofit web teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Headless content delivery for custom applications$q$, $q$Development teams use Plone's REST API and Volto frontend to power custom web and mobile apps from a single content backend.$q$, $q$Python-centric development teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$Open Source$q$, $q$Free$q$, $q$N/A, self-hosted$q$, NULL, $q$["Full CMS functionality","REST API and Volto headless frontend","Multilingual content management","Granular workflows and permissions","Community support via forums and documentation"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Plone is a free and open-source content management system built on the Zope application server and written in Python, with a modern React-based frontend for both traditional and headless website deployments.$q$, $q$The project traces back to 1999, was first publicly released in October 2001, and has been governed since 2004 by the nonprofit Plone Foundation, making it one of the longest-running formally governed open-source CMS projects.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Plone is widely known for a strong, long-standing security track record, along with deep built-in support for granular permissions, content workflows, multilingual sites and accessibility compliance out of the box.$q$, $q$It exposes a full REST API, enabling both traditional server-rendered websites and fully headless architectures via the Volto React frontend, making it attractive to development teams who want flexibility in how content is delivered.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Plone itself is completely free and open source, with no licensing fees, seat limits or vendor lock-in, and can be self-hosted on any infrastructure the organization chooses.$q$, $q$Costs organizations do incur typically come from hosting infrastructure and optional professional services, such as implementation, theming or support contracts, from independent Plone integrators rather than from the Plone Foundation itself.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('97866dd0-6dea-4e55-a594-ffa15a710dc6', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$Self-hosted deployment$q$, $q$Runs as a single Go binary that can be deployed on your own infrastructure and scaled horizontally.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$Collaborative whiteboard$q$, $q$Built-in whiteboard supporting PDF, DOCX and PPTX file annotation during meetings.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$Recording and live streaming$q$, $q$Record sessions as portable MP4 files or stream live to YouTube and Facebook via RTMP/WHIP.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$AI meeting agent$q$, $q$Provides live spoken translation, automated transcription and meeting summaries.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$End-to-end encryption$q$, $q$Optional E2EE support for privacy-sensitive meetings.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$White-label customization$q$, $q$Customize URLs, logos, branding colors and available features for a fully branded experience.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$Free, open-source and fully self-hostable with no per-seat licensing$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$Full control over data privacy and hosting infrastructure$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$Modern feature set including AI transcription, translation and summaries$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$Efficient single-binary deployment built on a proven WebRTC media stack (LiveKit)$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$Self-hosting requires server administration and DevOps expertise$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$Smaller community and ecosystem compared to Jitsi or BigBlueButton$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$Managed cloud pricing is not transparently published$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$Founding date and company details are not publicly disclosed$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$Is plugNmeet free?$q$, $q$Yes, the core plugNmeet software is free and open source for self-hosting; a managed cloud version is also available for those who prefer not to run their own servers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$What technology does plugNmeet use?$q$, $q$plugNmeet is built on Go, LiveKit for WebRTC media handling, and NATS for messaging, distributed as a single binary.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$Who maintains plugNmeet?$q$, $q$plugNmeet is maintained by MynaParrot, with its source code publicly available on GitHub.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$Can I brand plugNmeet with my own logo and colors?$q$, $q$Yes, plugNmeet supports white-label customization including custom URLs, logos and branding colors.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$Does plugNmeet support recording and live streaming?$q$, $q$Yes, it supports recording sessions as MP4 files and live streaming to platforms like YouTube and Facebook via RTMP/WHIP.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$Does plugNmeet have AI features?$q$, $q$Yes, plugNmeet includes an AI meeting agent for live translation, transcription and automated meeting summaries.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$What are the main alternatives to plugNmeet?$q$, $q$Common alternatives include Jitsi Meet, BigBlueButton and LiveKit Meet, along with commercial platforms like Zoom and Google Meet.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$Self-hosted company meetings$q$, $q$Organizations that need full data control deploy plugNmeet on their own infrastructure for internal video meetings.$q$, $q$IT and DevOps teams at privacy-conscious organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$White-labeled video conferencing for products$q$, $q$Software companies embed and rebrand plugNmeet as the video layer inside their own applications or platforms.$q$, $q$SaaS developers and platform builders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$Education and webinar hosting$q$, $q$Institutions use plugNmeet's whiteboard, recording and breakout room features to run online classes and webinars.$q$, $q$Educators and training organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$Self-Hosted$q$, $q$Free$q$, $q$Open source, one-time setup plus your own server hosting costs$q$, NULL, $q$["Full video conferencing feature set","Unlimited meetings and participants (hardware-dependent)","Recording and live streaming","AI meeting agent","White-label customization"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$plugNmeet Cloud$q$, $q$Custom (contact for pricing)$q$, $q$Managed hosting$q$, NULL, $q$["Fully managed hosting","No infrastructure to maintain","Same core feature set as self-hosted"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$plugNmeet is an open-source video conferencing platform designed to be self-hosted, built on WebRTC with LiveKit handling real-time media and NATS handling messaging, all wrapped in a Go server distributed as a single binary.$q$, $q$It is maintained by MynaParrot and made available as free, self-hostable software on GitHub, with an optional managed cloud version at plugnmeet.cloud for teams that don't want to run their own infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$plugNmeet supports HD audio and video calls with large camera grid views, screen sharing, a collaborative whiteboard with office file support, a shared notepad, polls and breakout rooms for structured meetings.$q$, $q$It also includes recording to portable MP4 files, RTMP/WHIP streaming to platforms like YouTube and Facebook, end-to-end encryption, and an AI meeting agent that offers live translation, transcription and automated meeting summaries.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core plugNmeet software is free and open source, and can be self-hosted on your own servers with no per-seat licensing fees, giving organizations full control over their data and deployment.$q$, $q$For teams that don't want to manage infrastructure themselves, the plugNmeet team also offers a managed cloud version at plugnmeet.cloud, though specific published pricing for that hosted service was not found in public sources.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6bb04494-9b4c-4959-9345-35cb07ffe59d', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$No database required$q$, $q$All content and settings are stored in XML files, eliminating the need for MySQL or any database setup.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$Portable sites$q$, $q$Entire websites can be backed up or moved with a simple file copy, even onto a USB drive.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$Multi-user permissions$q$, $q$Supports multiple users across five distinct permission levels for collaborative site management.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$No-code plugin system$q$, $q$Extend functionality through plugins without needing to write custom code.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$Customizable responsive themes$q$, $q$Mobile-friendly themes that can be customized to match a site's branding.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$Multilingual interface$q$, $q$Available in 11 languages including French, English, Spanish, German and Italian.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$Completely free and open source with no licensing costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$No database required, simplifying hosting and reducing attack surface$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$Extremely portable; sites can be moved with a simple file copy$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$Lightweight and fast, suited to minimal or low-cost hosting$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$Smaller international community and plugin ecosystem than WordPress$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$Flat-file storage can become slower on very large sites with many posts$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$Documentation and community support are strongest in French$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$Less suited to complex, high-traffic or e-commerce sites$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$Is PluXml free?$q$, $q$Yes, PluXml is completely free and open-source software released under the GNU General Public License.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$Does PluXml require a database?$q$, $q$No, PluXml stores all content and configuration in XML files, so no database like MySQL is required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$What does the name PluXml mean?$q$, $q$PluXml is a French portmanteau of 'plume' (feather) and 'XML', reflecting its lightweight, database-free design.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$What languages is PluXml available in?$q$, $q$PluXml is available in 11 languages, including French, English, Spanish, German, Italian, Dutch, Occitan, Polish, Portuguese, Romanian and Russian.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$Can I move a PluXml site easily?$q$, $q$Yes, because everything is stored as files rather than in a database, a PluXml site can be backed up or moved with a simple file copy, even onto a USB drive.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$Is PluXml good for large websites?$q$, $q$PluXml is best suited to small to medium sites and blogs; very large sites with many posts may see performance trade-offs compared to database-driven CMS platforms.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$What are the main alternatives to PluXml?$q$, $q$Alternatives include other flat-file CMS platforms like Grav, Kirby and Bludit, as well as WordPress for database-driven sites.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$Personal and family blogs$q$, $q$Individuals and families use PluXml for simple, low-maintenance personal blogs and photo journals without database overhead.$q$, $q$Individuals and hobbyist bloggers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$Small business websites$q$, $q$Small businesses use PluXml to run a lightweight informational website or blog on minimal, low-cost hosting.$q$, $q$Small business owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$Portable or offline-friendly sites$q$, $q$Users needing a site they can carry, demo or run from removable media choose PluXml for its file-based portability.$q$, $q$Developers and hobbyists needing portable deployments$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$Open Source$q$, $q$Free$q$, $q$N/A, self-hosted$q$, NULL, $q$["Full CMS and blogging functionality","No database required","Multi-user permissions","Plugin and theme system","Community support via forums and documentation"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PluXml is a free, open-source content management system and blogging platform that stores all site content and settings in XML files rather than a database, making it exceptionally lightweight and portable.$q$, $q$Originally a French-language project (its name blends the French word 'plume', meaning feather, with 'XML'), PluXml has since been translated into 11 languages and remains especially popular in French-speaking hosting and open-source communities.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Because PluXml requires no database, entire sites can be backed up, moved or run from removable media with a simple file copy, and hosting requirements are minimal compared to database-driven CMS platforms.$q$, $q$The platform includes multi-user support with five permission levels, customizable mobile-responsive themes, a no-code plugin system, RSS feeds, URL rewriting, comment management and static pages.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$PluXml is completely free and open source under the GNU General Public License, with no licensing fees or paid tiers of any kind.$q$, $q$The only cost involved is standard web hosting, and because PluXml has no database requirement, it can run on very inexpensive, minimal shared hosting plans.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eba0f7e5-197a-4285-93b2-3fcbd9da16ba', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Single-file deployment$q$, $q$Ships as one executable binary bundling the database, auth, storage and API server with no external dependencies.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Embedded SQLite database$q$, $q$Includes a visual schema builder, data validation rules and realtime subscriptions built on SQLite.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Built-in authentication$q$, $q$Supports email/password login and OAuth2 providers including Google, GitHub, GitLab and Facebook.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Realtime REST API$q$, $q$Auto-generated REST API with realtime subscription events delivered over WebSockets.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$File storage with thumbnails$q$, $q$Local or S3-compatible file storage with automatic image thumbnail generation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Extensible Go framework$q$, $q$Can be used standalone or extended with custom Go and JavaScript hooks for advanced backend logic.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Extremely simple to deploy as a single self-contained binary$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Completely free and open source with no per-user or usage-based fees$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Built-in admin dashboard, auth and file storage out of the box$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Lightweight and fast, thanks to its embedded SQLite foundation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$SQLite foundation makes horizontal scaling harder than Postgres-based alternatives$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Maintained largely by a single developer, which is a sustainability risk for critical projects$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Smaller ecosystem and fewer managed hosting options than Supabase or Firebase$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Fewer enterprise features (like advanced row-level security policies) than larger platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Is PocketBase free?$q$, $q$Yes, PocketBase is free and open-source software under the MIT license, with no subscription fees for the software itself.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Who created PocketBase?$q$, $q$PocketBase was created by developer Gani Georgiev and launched in 2022.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$What database does PocketBase use?$q$, $q$PocketBase uses an embedded SQLite database, bundled directly into its single executable file.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Can PocketBase scale to production use?$q$, $q$Yes, PocketBase can power small-to-medium production apps, though its SQLite foundation makes it better suited to smaller-scale deployments than large, horizontally scaled applications.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Does PocketBase support authentication?$q$, $q$Yes, PocketBase includes built-in email/password authentication and OAuth2 support for providers like Google, GitHub and GitLab.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$How is PocketBase different from Supabase or Firebase?$q$, $q$PocketBase is a single-binary, SQLite-based backend you self-host yourself, offering much simpler setup than Supabase or Firebase, which are larger, Postgres-based (Supabase) or proprietary (Firebase) managed platforms.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Can I extend PocketBase with custom backend logic?$q$, $q$Yes, PocketBase can be used as a Go framework, letting developers add custom hooks, routes and business logic beyond the default REST API.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$MVPs and side projects$q$, $q$Indie developers use PocketBase to spin up a working backend with auth and a database in minutes for prototypes and side projects.$q$, $q$Indie developers and hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Internal tools and admin panels$q$, $q$Small teams use PocketBase to quickly build internal tools and admin dashboards without standing up separate backend infrastructure.$q$, $q$Small engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Self-hosted apps with data control$q$, $q$Developers who want full control over their data and hosting choose PocketBase over managed cloud backends to avoid vendor lock-in.$q$, $q$Privacy-conscious developers and small businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$Open Source$q$, $q$Free$q$, $q$N/A, self-hosted$q$, NULL, $q$["Embedded SQLite database","Built-in authentication and OAuth2","Realtime REST API","File storage with thumbnails","Admin dashboard UI","Community support via GitHub and Discord"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PocketBase is an open-source backend-as-a-service that ships as a single executable file, combining an embedded SQLite database, authentication, file storage and a realtime REST API into one self-contained package.$q$, $q$Created by developer Gani Georgiev and launched in 2022, PocketBase is released under the MIT license and remains a largely solo-maintained open-source project, funded partly through GitHub Sponsors and open-source funding initiatives.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$PocketBase provides an embedded SQLite database with a visual schema builder and data validation rules, a built-in admin dashboard UI, and realtime subscriptions delivered over WebSockets so apps can react to data changes instantly.$q$, $q$It also handles user authentication out of the box, including email/password and OAuth2 providers like Google, GitHub and GitLab, plus local or S3-compatible file storage with automatic thumbnail generation, and can be extended as a Go framework with custom hooks.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$PocketBase itself is completely free and open source, with no licensing fees, per-user charges or subscription tiers for the software.$q$, $q$The only cost is wherever you choose to host the single binary, whether a low-cost VPS, a cloud VM, or even a local machine, which typically works out far cheaper than usage-based managed backend-as-a-service platforms.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e6c72275-7cb5-4d25-b407-ad1b09e419ab', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
