-- ── plugNmeet ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$plugNmeet is an open-source, self-hosted video conferencing platform built on WebRTC, LiveKit, Go and NATS, offering HD calls, recording, whiteboarding and AI meeting features as a single deployable binary.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); managed cloud hosting also available$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (small team)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$plugNmeet Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$plugNmeet is a self-hosted, open-source WebRTC video conferencing platform. See its features, deployment options and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$plugNmeet is an open-source, self-hosted video conferencing platform built on WebRTC, using Go for its core server, LiveKit for real-time media handling, and NATS for messaging, and distributed as a single efficient binary designed for straightforward installation and horizontal scaling. It is maintained by MynaParrot, the small team behind the project, with the source code hosted publicly on GitHub under the mynaparrot organization; the project does not publish a specific founding year but has been under active development with regular feature releases. plugNmeet's key differentiator versus larger commercial video platforms is that it is fully self-hostable and free to run on your own infrastructure, giving organizations complete data control and no per-seat licensing costs, while still offering a feature set comparable to commercial tools: HD audio and video with support for large camera grid views, screen sharing, a collaborative whiteboard with office document support (PDF, DOCX, PPTX), a shared notepad, polls, breakout rooms, recording to portable MP4 files, RTMP/WHIP live streaming to platforms like YouTube and Facebook, end-to-end encryption, and an AI meeting agent that provides live translation, transcription and automated meeting summaries. Beyond the free self-hosted option, the team also offers plugnmeet.cloud, a managed hosted version for organizations that want the software without running their own servers, giving plugNmeet a hybrid open-source-plus-managed-cloud pricing model rather than a purely enterprise-license approach. Its target users are organizations, educational institutions, and developers who want a privacy-respecting, customizable, white-labelable video conferencing solution they can brand and control themselves, ranging from small teams self-hosting on a single server to larger deployments scaling horizontally across multiple nodes. plugNmeet competes with other open-source, self-hostable video conferencing platforms such as Jitsi Meet and BigBlueButton (the latter more focused on education and webinars), as well as LiveKit Meet (built on the same underlying media engine), and indirectly with commercial hosted platforms like Zoom and Google Meet for organizations weighing self-hosted control against convenience.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6bb04494-9b4c-4959-9345-35cb07ffe59d';

