  company_size = COALESCE($q$Not publicly disclosed (volunteer open-source project)$q$, company_size),
  headquarters = COALESCE($q$France (volunteer open-source project)$q$, headquarters),
  languages = ARRAY[$q$French$q$, $q$English$q$, $q$Spanish$q$, $q$German$q$, $q$Italian$q$, $q$Dutch$q$, $q$Occitan$q$, $q$Polish$q$, $q$Portuguese$q$, $q$Romanian$q$, $q$Russian$q$]::text[],
  seo_title = COALESCE($q$PluXml Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$PluXml is a free, open-source, database-free blogging CMS that stores content in XML files. See its features, pros, cons and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$PluXml is a free, open-source, flat-file content management system and blogging platform that stores all content and configuration in XML files rather than a traditional database, making entire sites portable enough to move or back up with a simple file copy, including onto a USB drive. Its name is a French portmanteau of 'plume' (feather, evoking lightness) and 'XML', reflecting both its French origins and its no-database design philosophy; it was originally developed and released in French before later being internationalized and translated into 11 languages, including English, Spanish, German, Italian, Dutch, Occitan, Polish, Portuguese, Romanian and Russian. PluXml is released under the GNU General Public License and is maintained as a community open-source project, with source code publicly hosted on GitHub, rather than being backed by a commercial company; specific founding year and team details are not publicly documented in detail, though the project has been actively maintained for many years and remains popular within French-speaking web hosting and open-source communities. Its core differentiator versus mainstream CMS platforms like WordPress is the complete absence of a database dependency: because all posts, pages, categories, comments and settings are stored as XML files, PluXml requires no MySQL setup, and sites can be hosted on extremely minimal, low-cost shared hosting, or even carried on removable media, with no database administration burden. Being fully free and open source, there is no pricing model or licensing fee; costs are limited entirely to whatever web hosting a user chooses. Key features include multi-user support with five distinct permission levels, customizable and mobile-responsive themes, a plugin system for extending functionality without writing code, RSS feeds, URL rewriting, comment management and static pages. PluXml's target users are individuals, families, small businesses and organizations who want a very lightweight, low-maintenance blog or simple website without the overhead, security surface, or hosting requirements of a database-driven CMS. Its closest competitors are other flat-file content management systems such as Grav, Kirby and Bludit, all of which similarly avoid databases, as well as WordPress, the dominant database-driven CMS that PluXml positions itself as a lighter-weight, simpler alternative to for small sites and personal blogs.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'eba0f7e5-197a-4285-93b2-3fcbd9da16ba';

