-- ── PocketBase ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$PocketBase is an open-source backend-as-a-service distributed as a single executable file, bundling an embedded SQLite database, authentication, file storage and a real-time REST API for building apps quickly.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$1 employee (solo-maintained project)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$PocketBase Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$PocketBase is a free, open-source backend in a single file with SQLite, auth and realtime APIs. See features, pros, cons and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$PocketBase is a free and open-source backend-as-a-service written in Go, distributed as a single portable executable file that bundles an embedded SQLite database, user authentication, file storage, and a realtime REST API into one lightweight package with no external dependencies. It was created by developer Gani Georgiev and launched in 2022, and remains largely a solo-maintained open-source project released under the MIT license, funded in part through GitHub Sponsors and open-source funding programs like FLOSS/Fund rather than backed by a venture-funded company. PocketBase's core differentiator is radical simplicity and portability: rather than requiring a cloud account, multiple services, or complex infrastructure like larger backend-as-a-service platforms, a developer downloads one binary, runs it, and immediately has a working backend with a built-in admin dashboard UI, schema builder, data validation rules, realtime subscriptions over WebSockets, and authentication supporting email/password and OAuth2 providers like Google, GitHub, GitLab and Facebook. It can be used purely as a standalone server or extended as a Go framework with custom hooks and routes, and offers client SDKs for JavaScript and Dart, making it straightforward to pair with frontend frameworks like React, Vue, Angular, Svelte or Flutter. Because PocketBase is entirely free, open-source, and self-hosted, there is no pricing model or subscription tiers for the software itself; the only associated costs come from wherever a developer chooses to deploy the binary, such as a small VPS or cloud instance, which tends to be far cheaper than managed backend-as-a-service platforms billed per active user or database row. Its target users are indie developers, small teams, and hobbyists building MVPs, side projects, admin panels or small-to-medium production apps who want Firebase- or Supabase-like convenience without vendor lock-in, ongoing per-user billing, or the operational complexity of running a full Postgres-based backend. PocketBase's most commonly cited competitors and alternatives are Supabase and Firebase, both larger and more feature-rich (and typically Postgres-based rather than SQLite-based) backend-as-a-service platforms, along with Appwrite and Hasura, though PocketBase differentiates itself specifically through its single-binary simplicity and SQLite foundation, which trades some horizontal scalability for dramatically easier setup and self-hosting.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e6c72275-7cb5-4d25-b407-ad1b09e419ab';

